def assemble_section(section: str, source_path: str) -> dict:
    """Run one Claude pass per section; tag every claim with source."""
    content = open(source_path).read()
    prompt = f"Assemble the {section} section. After every claim, append [source: {source_path}]."
    # Claude call here returns tagged content
