def detect_conflicts(sections: list[dict]) -> list[dict]:
    """Flag claims that appear in multiple sources with contradictory values."""
    conflicts = []
    claim_map = {}
    for s in sections:
        for claim in s.get("claims", []):
            key = claim["key"]
            if key in claim_map and claim_map[key]["value"] != claim["value"]:
                conflicts.append({"key": key, "sources": [claim_map[key], claim]})
            claim_map[key] = claim
    return conflicts
